// n8n Code node (JavaScript)
// Devuelve 1 item con el body listo para ManyChat

const subscriberId = $input.first().json?.subscriber_id
  ?? $node["Webhook1"]?.json?.body?.["ID del usuario"]
  ?? $node["Webhook1"]?.json?.body?.["ID del usuario"]
  ?? null;

if (!subscriberId) {
  throw new Error("No encuentro subscriber_id. Revisá Webhook1.body['ID del usuario'] o pasalo por input.");
}

const respuestas = $input.first().json?.output?.respuesta
  ?? $node["Basic LLM Chain1"]?.json?.output?.respuesta
  ?? [];

const fieldMap = [
  12531357, // [0]
  12531358, // [1]
  12531359, // [2]
  14116939, // [3]
  14116941, // [4]
  14116942, // [5]
  14116960, // [6]
  14131051, // [7]
  14131052, // [8]
  14131055, // [9]
  14131056, // [10]
  14131057  // [11]
];

const fields = (Array.isArray(respuestas) ? respuestas : [])
  .map((value, index) => {
    if (!fieldMap[index]) return null;
    if (value === null || value === undefined) return null;

    const v = String(value).trim();
    if (!v) return null;

    return { field_id: fieldMap[index], field_value: v };
  })
  .filter(Boolean);

return [
  {
    json: {
      subscriber_id: subscriberId,
      fields
    }
  }
];

