  (() => {
    const ids = [
      12531357, // response_part1 -> index 0
      12531358, // response_part2
      12531359,
      14116939,
      14116941,
      14116942,
      14116960,
      14131051,
      14131052,
      14131055,
      14131056,
      14131057  // response_part12 -> index 11
    ];

    const value = String($json.mensajes ?? '');

    // contar SOLO los "1", ignorando "=" u otros caracteres
    const countOnes = (value.match(/1/g) || []).length;

    // si no hay 1s, no devuelve nada (podés cambiarlo si querés)
    if (countOnes === 0) return null;

    // devolver el id correspondiente (1 → index 0, 2 → index 1, etc.)
    return ids[countOnes - 1] ?? null;
  })()
}}

