// Recorremos todos los items
for (const item of $input.all()) {

  // El campo URL es un string JSON
  const raw = item.json.URL;

  if (!raw) {
    continue;
  }

  let parsed;

  try {
    parsed = JSON.parse(raw);
  } catch (e) {
    throw new Error('El campo URL no es un JSON válido');
  }

  // Extraemos y normalizamos campos
  item.json.mimeType = parsed.mimeType || null;
  item.json.fileType = parsed.fileType || null;
  item.json.fileExtension = parsed.fileExtension || null;
  item.json.fileName = parsed.fileName || null;
  item.json.fileSize = parsed.fileSize || null;

  // Esta es la URL REAL del archivo
  item.json.mediaUrl = parsed.directory || null;
}

// Devolvemos los items modificados
return $input.all();

